mapper.select:
SELECT u.user_code, u.user_name, u.email, u.profile_image, CASE WHEN m2.user_code IS NOT NULL THEN 1 ELSE 0 END AS isAlreadyMember FROM users u LEFT JOIN members m2 ON u.user_code = m2.user_code AND m2.project_id = #{projectId} WHERE u.status = 'a2' AND u.company_id = #{companyId}
AND u.user_name LIKE '%' || #{keyword} || '%'
ORDER BY isAlreadyMember DESC, u.user_name

